import{_ as e,r as o,o as c,c as s,d as n,f as a}from"./app-19f36e20.js";const p="/godot/images/node_tree.png",i={},r=a('<div class="custom-container tip"><p class="custom-container-title">游戏、场景与节点之间的关系？</p><p>一个场景 == 根节点 + N 个子节点</p><p>一个游戏 == N 个场景</p></div><p>在 Godot 中，节点是构建游戏最基本的元素。就像人类食谱中的食材一样。Godot 引擎包含很多种节点，可以用来显示图像、播放声音、表示摄像机等等。</p><p>但是，但单个节点本身不能做很多事情。为了充分挖掘其潜力，需要将其与其他节点结合起来，这样就形成了场景。</p><p>所以说，一个场景只不过是一个节点，加上它的子节点们，形成的一个树形结构。所以，场景又被称为节点树（如下图所示）。</p><p><img src="'+p+'" alt="节点树"></p><div class="custom-container tip"><p class="custom-container-title">思考：场景与场景之间的关系？</p><p>场景可以被保存到磁盘上，然后被实例化到其他场景中。这使得 Godot 项目的架构和数据模型具有非常高的灵活性。</p></div><div class="custom-container danger"><p class="custom-container-title">注意事项</p><p>值得注意的是，一个场景只有一个父节点(称为根节点)，但可以有任意数量的子节点。</p></div>',7);function d(l,_){const t=o("PageHeader");return c(),s("div",null,[n(t,{content:"游戏、场景与节点之间的关系？"}),r])}const u=e(i,[["render",d],["__file","what-scene.html.vue"]]);export{u as default};
